// Главный парсер входящих Telegram-сообщений.
// Определяет тип сообщения и извлекает данные:
//   команда /cmd --flags args      → command_candidate
//   /abort [task-key]               → abort_request
//   ответ на pending-задачу         → answer_candidate
//   ничего не понятно               → parse_error

const input = $('Триггер Telegram').first().json
const msg = input.message || {}
const rawText = String(msg.text || '').trim()
const pendingTasks = $('Получаем задачи с ожиданием ответа').all().map((item) => item.json)

// Разбирает /command из текста, отделяя @botname
function parseCommand(text) {
  const match = text.match(/^\/([a-zA-Z0-9_]+)(?:@\w+)?(?:\s+|$)/)
  if (!match) return { type: null, textAfterCommand: text }
  return { type: match[1], textAfterCommand: text.slice(match[0].length).trim() }
}

// Разбирает токены: "строка" 'строка' --флаг --флаг=значение аргумент
function parseTokens(text) {
  const flags = {}
  const args = []
  const regex = /"([^"]*)"|'([^']*)'|--([a-zA-Z0-9_-]+)(?:=(?:"([^"]*)"|'([^']*)'|([^\s"']+)))?|([^\s]+)/g
  let match
  while ((match = regex.exec(text)) !== null) {
    if (match[3]) {
      const key = match[3]
      const value = match[4] ?? match[5] ?? match[6] ?? true
      flags[key] = value
      continue
    }
    const value = match[1] ?? match[2] ?? match[7]
    if (value !== undefined) args.push(value)
  }
  return { flags, args }
}

// Подсказка при нескольких pending-задачах: список + формат ответа
function buildPendingTasksHint(tasks) {
  const taskList = tasks.map((task) => `- ${task.task_key || 'неизвестно'}`).join('\n')
  return [
    'Сейчас OpenCode ждёт ответ по нескольким задачам.',
    taskList, '',
    'Ответьте в формате `task_key: ваш ответ`.',
    'Для отклонения вопроса используйте `task_key: /reject`.',
  ].join('\n')
}

// Пытаемся распознать ответ на pending-задачу:
//   task-key: текст ответа  → целевой ответ
//   /reject [task-key]      → отклонение
//   обычный текст           → если одна задача — ответ на неё
function parseAnswerTarget(text, tasks) {
  const targetedMatch = text.match(/^#?(task-[a-z0-9-]+)\s*:\s*([\s\S]*)$/i)
  if (targetedMatch) {
    return { taskKey: targetedMatch[1], answerText: String(targetedMatch[2] || '').trim(), rejectRequested: false }
  }
  const rejectMatch = text.match(/^\/?(reject|skip|cancel)\b(?:\s+(task-[a-z0-9-]+))?$/i)
  if (rejectMatch) {
    if (!rejectMatch[2] && tasks.length > 1) return { multiplePending: true }
    return { taskKey: String(rejectMatch[2] || '').trim(), answerText: '/reject', rejectRequested: true }
  }
  if (text.startsWith('/')) return null
  if (tasks.length === 1) return { taskKey: String(tasks[0].task_key || '').trim(), answerText: text, rejectRequested: false }
  if (tasks.length > 1) return { multiplePending: true }
  return null
}

// --- Основная логика ---
const answerTarget = parseAnswerTarget(rawText, pendingTasks)

if (answerTarget?.multiplePending) {
  return [{ json: { mode: 'parse_error', rawText, replyText: buildPendingTasksHint(pendingTasks) } }]
}

if (answerTarget) {
  return [{ json: { mode: 'answer_candidate', rawText, targetTaskKey: answerTarget.taskKey || (pendingTasks.length === 1 ? String(pendingTasks[0].task_key || '').trim() : ''), answerText: answerTarget.answerText, rejectRequested: answerTarget.rejectRequested === true, replyText: '' } }]
}

const abortMatch = rawText.match(/^\/abort\b(?:\s+(task-[a-z0-9-]+))?$/i)
if (abortMatch) {
  return [{ json: { mode: 'abort_request', rawText, targetTaskKey: String(abortMatch[1] || '').trim(), replyText: '' } }]
}

if (rawText.startsWith('/')) {
  const command = parseCommand(rawText)
  const parsed = parseTokens(command.textAfterCommand)
  const newSessionRequested = Boolean(
    parsed.flags['new-session'] || parsed.flags['new_session'] ||
    parsed.flags['fresh-session'] || parsed.flags['fresh_session']
  )
  return [{ json: { mode: 'command_candidate', rawText, commandType: command.type, flags: parsed.flags, args: parsed.args, parentTaskId: String(parsed.flags['parent-id'] || parsed.flags.parent || '').trim(), parentMatchText: String(parsed.flags.match || parsed.flags.contains || '').trim(), prompt: String(parsed.flags.prompt || '').trim(), newSessionRequested, replyText: '' } }]
}

return [{ json: { mode: 'parse_error', rawText, replyText: pendingTasks.length > 0 ? 'Не удалось понять сообщение. Для ответа по задаче используйте `task_key: ваш ответ`, либо пришлите обычный текст, если ожидается только один вопрос.' : 'Команда распарсена с ошибкой' } }]

// Связываем candidate из парсера с конкретной pending-задачей.
// Извлекаем из pending_options_json метаданные интеракции (requestId, тип).

const candidate = $('Разбираем базовое сообщение Telegram').first().json
const pendingTasks = $('Получаем задачи с ожиданием ответа').all().map((item) => item.json)

function parsePendingMeta(task) {
  try { return JSON.parse(String(task.pending_options_json || '{}')) } catch { return {} }
}

const task = pendingTasks.find(
  (item) => String(item.task_key || '').trim() === String(candidate.targetTaskKey || '').trim()
)
if (!task) {
  return [{ json: { mode: 'parse_error', replyText: `Не удалось найти задачу ${candidate.targetTaskKey || 'неизвестно'} среди ожидающих ответа.` } }]
}

const pendingMeta = parsePendingMeta(task)
const requestId = String(pendingMeta.requestId || '').trim()
const interactionType = Array.isArray(pendingMeta.questions) ? 'question' : String(pendingMeta.type || 'permission').trim()

if (!requestId) {
  return [{ json: { mode: 'parse_error', replyText: `У задачи ${candidate.targetTaskKey || 'неизвестно'} повреждены данные pending интеракции.` } }]
}

return [{
  json: {
    mode: interactionType + '_candidate',
    rawText: candidate.rawText,
    targetTaskKey: candidate.targetTaskKey,
    answerText: candidate.answerText,
    rejectRequested: candidate.rejectRequested === true,
    interactionType,
    pendingMeta,
  },
}]

// Готовим запрос на прерывание задачи.

const parsed = $('Разбираем базовое сообщение Telegram').first().json
const inputTaskKey = String(parsed.targetTaskKey || '').trim()

return [{ json: { mode: 'abort_request', rawText: parsed.rawText, targetTaskKey: inputTaskKey } }]

// Определяем какую задачу прерывать.
//   явный task-key      → указанная задача
//   без task-key         → если одна — авто-выбор, несколько — уточнение у пользователя

const abortRequest = $('Готовим запрос прерывания').first().json
const activeRunning = $('Получаем работающие задачи').all().map((item) => item.json)
const inputTaskKey = String(abortRequest.targetTaskKey || '').trim()

if (activeRunning.length === 0) {
  return [{ json: { mode: 'parse_error', replyText: 'Нет работающих задач, которые можно прервать.' } }]
}

if (inputTaskKey) {
  const task = activeRunning.find((item) => String(item.task_key || '').trim() === inputTaskKey)
  if (!task) {
    return [{ json: { mode: 'parse_error', replyText: `Не удалось найти работающую задачу ${inputTaskKey || 'неизвестно'}.` } }]
  }
  return [{ json: { mode: 'answer', targetTaskKey: inputTaskKey, replyText: `Задача ${inputTaskKey} будет прервана.` } }]
}

if (activeRunning.length === 1) {
  const taskKey = String(activeRunning[0].task_key || '').trim()
  return [{ json: { mode: 'answer', targetTaskKey: taskKey, replyText: `Задача ${taskKey} будет прервана.` } }]
}

const taskList = activeRunning.map((item) => `- ${item.task_key || 'неизвестно'}`).join('\n')
return [{ json: { mode: 'parse_error', replyText: `Работает несколько задач:\n${taskList}\n\nУточните: /abort task-key` } }]

// Парсим ответ пользователя на question-интеракцию OpenCode.
// Поддерживает:
//   - один вопрос → простой ответ (номер/текст варианта)
//   - несколько вопросов → ответы через перенос строки
//   - /reject → отклонение вопроса
//   - множественный выбор → варианты через запятую

const parsed = $('Готовим ожидающую интеракцию').first().json
const pendingMeta = parsed.pendingMeta || {}
const normalized = String(parsed.answerText || '').trim()

// Отклонение вопроса
if (parsed.rejectRequested) {
  const updatedPendingMeta = {
    ...pendingMeta,
    answers: null,
    rejectRequested: true,
    answeredAt: new Date().toISOString(),
    rawAnswer: parsed.rawText,
  }
  return [{ json: { mode: 'answer', targetTaskKey: parsed.targetTaskKey, updatedPendingOptionsJson: JSON.stringify(updatedPendingMeta), replyText: `Вопрос по задаче ${parsed.targetTaskKey || 'неизвестно'} отклонён.` } }]
}

// Разбирает один токен ответа: число → номер варианта, текст → поиск по label
function parseAnswerToken(token, question) {
  const value = String(token || '').trim()
  if (!value) return null
  const options = Array.isArray(question.options) ? question.options : []
  if (options.length === 0) return value
  if (/^\d+$/.test(value)) {
    const option = options[Number(value) - 1]
    return option ? String(option.label || '').trim() : null
  }
  const matched = options.find((option) => String(option.label || '').trim().toLowerCase() === value.toLowerCase())
  if (matched) return String(matched.label || '').trim()
  return question.custom !== false ? value : null
}

// Разбирает ответ на один вопрос: возвращает { answers } или { error }
function parseQuestionAnswer(text, question) {
  const value = String(text || '').trim()
  if (!value) return { error: 'Ответ не должен быть пустым.' }
  const options = Array.isArray(question.options) ? question.options : []
  if (options.length === 0) return { answers: [value] }
  const tokens = question.multiple ? value.split(/\s*,\s*/).filter(Boolean) : [value]
  const answers = []
  for (const token of tokens) {
    const parsedToken = parseAnswerToken(token, question)
    if (!parsedToken) return { error: `Не удалось распознать вариант ответа: ${token}` }
    if (!answers.includes(parsedToken)) answers.push(parsedToken)
  }
  if (!question.multiple && answers.length !== 1) {
    return { error: 'Нужно выбрать ровно один вариант ответа.' }
  }
  return { answers }
}

const questions = Array.isArray(pendingMeta.questions) ? pendingMeta.questions : []
if (questions.length === 0) {
  return [{ json: { mode: 'parse_error', replyText: `У задачи ${parsed.targetTaskKey || 'неизвестно'} повреждены данные pending вопроса.` } }]
}

// Один вопрос или несколько (через перенос строки)
let answersResult
if (questions.length === 1) {
  answersResult = parseQuestionAnswer(normalized, questions[0])
} else {
  const lines = normalized.split(/\r?\n/).map((line) => line.trim()).filter(Boolean)
  if (lines.length !== questions.length) {
    answersResult = { error: `Нужно прислать ${questions.length} непустых строк ответа в том же порядке, что и вопросы.` }
  } else {
    const answers = []
    for (let index = 0; index < questions.length; index += 1) {
      const parsedLine = parseQuestionAnswer(lines[index], questions[index])
      if (parsedLine.error) { answersResult = parsedLine; break }
      answers.push(parsedLine.answers)
    }
    answersResult = answersResult || { answers }
  }
}

if (answersResult.error) {
  return [{ json: { mode: 'parse_error', replyText: `Не удалось разобрать ответ для задачи ${parsed.targetTaskKey || 'неизвестно'}: ${answersResult.error}` } }]
}

const updatedPendingMeta = {
  ...pendingMeta,
  answers: answersResult.answers,
  rejectRequested: false,
  answeredAt: new Date().toISOString(),
  rawAnswer: parsed.rawText,
}

return [{ json: { mode: 'answer', targetTaskKey: parsed.targetTaskKey, updatedPendingOptionsJson: JSON.stringify(updatedPendingMeta), replyText: `Ответ по задаче ${parsed.targetTaskKey || 'неизвестно'} сохранён. Продолжаю выполнение.` } }]

// Парсим ответ пользователя на permission-интеракцию OpenCode.
// Варианты: 1/once, 2/always, 3/reject (с опциональным комментарием).

const parsed = $('Готовим ожидающую интеракцию').first().json
const pendingMeta = parsed.pendingMeta || {}
const normalized = String(parsed.answerText || '').trim()

if (!normalized) {
  return [{ json: { mode: 'parse_error', replyText: 'Ответ не должен быть пустым.' } }]
}

const lower = normalized.replace(/^\//, '').toLowerCase()
let reply = ''
let message = ''

if (/^(1|once|allow once|раз|один раз|разрешить один раз)(?:\b|$)/i.test(lower)) {
  reply = 'once'
} else if (/^(2|always|remember|always allow|всегда|запомнить|разрешить всегда)(?:\b|$)/i.test(lower)) {
  reply = 'always'
} else {
  const rejectMatch = lower.match(/^(3|reject|deny|no|отклонить|запретить)(?:[\s:,-]+([\s\S]*))?$/i)
  if (rejectMatch) {
    reply = 'reject'
    message = String(rejectMatch[2] || '').trim()
  }
}

if (!reply) {
  return [{ json: { mode: 'parse_error', replyText: `Не удалось разобрать permission-ответ для задачи ${parsed.targetTaskKey || 'неизвестно'}: Для permission используйте один из вариантов: 1/once, 2/always, 3/reject.` } }]
}

const updatedPendingMeta = {
  ...pendingMeta,
  type: 'permission',
  reply,
  message,
  answeredAt: new Date().toISOString(),
  rawAnswer: parsed.rawText,
}

return [{ json: { mode: 'answer', targetTaskKey: parsed.targetTaskKey, updatedPendingOptionsJson: JSON.stringify(updatedPendingMeta), replyText: `Permission-ответ по задаче ${parsed.targetTaskKey || 'неизвестно'} сохранён. Продолжаю выполнение.` } }]
